
import base64, subprocess, sys

# Write whale_scanner.py
scanner = base64.b64decode("").decode()
with open("/opt/polymarket-agent/whale_scanner.py", "w") as f:
    f.write(scanner)
print(f"whale_scanner.py written: {len(scanner)} chars")

# Write whale_monitor.py  
monitor = base64.b64decode("").decode()
with open("/opt/polymarket-agent/whale_monitor.py", "w") as f:
    f.write(monitor)
print(f"whale_monitor.py written: {len(monitor)} chars")

# Run whale_scanner
print("\nRunning whale_scanner.py...")
sys.stdout.flush()
result = subprocess.run(
    ["/opt/polymarket-agent/venv/bin/python3", "/opt/polymarket-agent/whale_scanner.py"],
    cwd="/opt/polymarket-agent",
    capture_output=True, text=True, timeout=120
)
print(result.stdout[-2000:] if len(result.stdout) > 2000 else result.stdout)
if result.stderr: print("STDERR:", result.stderr[-500:])
print(f"Scanner exit code: {result.returncode}")
